class Transport(str, Enum):
    """MCP transport modes."""
    stdio = "stdio"
    http = "http"
    streamable_http = "streamable-http"


class Provider(str, Enum):
    """Supported MCP client providers."""
    claude = "claude"
    vscode = "vscode"
    cursor = "cursor"
    codex = "codex"


